    96→		opts, err := settings.HTTPClientOptions(ctx)
    97→		if err != nil {
    98→			return nil, backend.DownstreamError(fmt.Errorf("error reading settings: %w", err))
    99→		}
   100→		opts.ForwardHTTPHeaders = true
   101→
   102→		client, err := httpClientProvider.New(opts)
   103→		if err != nil {
   104→			return nil, backend.DownstreamError(fmt.Errorf("error creating http client: %w", err))
   105→		}
